SELECT a.appointment_id, a.customer_id, a.customer_name, a.customer_phone, a.staff_id, a.service_id, a.appointment_date, a.start_time, a.end_time, a.end_datetime, a.total_duration, a.total_days, a.billing_type, a.service_address, a.special_requirements, a.status, a.accept_time, a.paid_time, a.total_amount, a.create_time, a.update_time, s.service_name, st.name AS staff_name, p.payment_status FROM appointment a LEFT JOIN service s ON a.service_id = s.service_id LEFT JOIN staff st ON a.staff_id = st.staff_id LEFT JOIN payment p ON a.appointment_id = p.appointment_id
AND a.customer_id = #{customerId} AND a.staff_id = #{staffId} AND a.status = #{status} AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate}
ORDER BY a.appointment_date DESC, a.start_time DESC
